"""
Tool Schema Validator
Validates tool calls against actual tool signatures to prevent hallucinated parameters.
"""

from typing import Dict, List, Any, Optional, Tuple


class ToolSchemaValidator:
    """
    Validates tool calls against known tool schemas.
    Prevents execution of calls with invalid/hallucinated parameters.
    """

    def __init__(self):
        """Initialize with actual tool parameter schemas"""
        # Define ACTUAL tool signatures (from tool_manager.py)
        self.tool_schemas = {
            'file_read': {
                'required': ['file_path'],
                'optional': ['encoding'],
                'all_params': {'file_path', 'encoding'}
            },
            'file_write': {
                'required': ['file_path', 'content'],
                'optional': ['encoding', 'mode'],
                'all_params': {'file_path', 'content', 'encoding', 'mode'}
            },
            'file_edit': {
                'required': ['file_path', 'old_content', 'new_content'],
                'optional': ['encoding'],
                'all_params': {'file_path', 'old_content', 'new_content', 'encoding'}
            },
            'bash_execute': {
                'required': ['command'],
                'optional': ['timeout', 'check', 'cwd'],
                'all_params': {'command', 'timeout', 'check', 'cwd'}
            },
            'grep_search': {
                'required': ['pattern'],
                'optional': ['path', 'file_pattern', 'context_lines', 'ignore_case'],
                'all_params': {'pattern', 'path', 'file_pattern', 'context_lines', 'ignore_case'}
            },
            'git_operations': {
                'required': ['operation'],
                'optional': ['args', 'path'],
                'all_params': {'operation', 'args', 'path'}
            },
            'file_search': {
                'required': [],
                'optional': ['pattern', 'path', 'file_type', 'max_results'],
                'all_params': {'pattern', 'path', 'file_type', 'max_results'}
            },
        }

        # Track rejected parameters for learning
        self.rejection_stats = {}

    def validate_tool_call(self, tool_name: str, args: Dict[str, Any]) -> Tuple[bool, List[str], Dict[str, Any]]:
        """
        Validate tool call against schema.

        Args:
            tool_name: Name of the tool
            args: Arguments provided

        Returns:
            Tuple of (is_valid, warnings, filtered_args)
            - is_valid: False if critical validation failed
            - warnings: List of warning messages
            - filtered_args: Args with hallucinated params removed
        """
        warnings = []
        filtered_args = {}

        # Unknown tool - can't validate
        if tool_name not in self.tool_schemas:
            return True, [f"Unknown tool '{tool_name}' - cannot validate"], args

        schema = self.tool_schemas[tool_name]

        # Check for required parameters
        for required_param in schema['required']:
            if required_param not in args:
                warnings.append(f"Missing required parameter: '{required_param}'")
                return False, warnings, {}

        # Filter out hallucinated parameters
        for param_name, param_value in args.items():
            if param_name in schema['all_params']:
                filtered_args[param_name] = param_value
            else:
                # Hallucinated parameter!
                warnings.append(f"Removed hallucinated parameter: '{param_name}' (not in schema)")
                self._track_rejection(tool_name, param_name)

        # If all required params filtered out, fail
        for required_param in schema['required']:
            if required_param not in filtered_args:
                return False, warnings, filtered_args

        return True, warnings, filtered_args

    def _track_rejection(self, tool_name: str, param_name: str):
        """Track which parameters get rejected most often"""
        key = f"{tool_name}.{param_name}"
        self.rejection_stats[key] = self.rejection_stats.get(key, 0) + 1

        # Auto-save rejection stats periodically (every 10 rejections)
        if sum(self.rejection_stats.values()) % 10 == 0:
            self._save_rejection_stats()

    def _save_rejection_stats(self):
        """Persist rejection stats to disk for analysis"""
        try:
            import json
            from pathlib import Path

            stats_dir = Path('logs') / 'validation'
            stats_dir.mkdir(parents=True, exist_ok=True)
            stats_file = stats_dir / 'parameter_rejections.json'

            # Load existing stats if present
            existing_stats = {}
            if stats_file.exists():
                with open(stats_file, 'r') as f:
                    existing_stats = json.load(f)

            # Merge with current stats
            for key, count in self.rejection_stats.items():
                existing_stats[key] = existing_stats.get(key, 0) + count

            # Save merged stats
            with open(stats_file, 'w') as f:
                json.dump(existing_stats, f, indent=2, sort_keys=True)

        except Exception:
            pass  # Silently fail - this is optional logging

    def get_rejection_stats(self) -> Dict[str, int]:
        """Get statistics on rejected parameters (for debugging/improvement)"""
        return dict(sorted(self.rejection_stats.items(), key=lambda x: x[1], reverse=True))

    def get_top_hallucinations(self, limit: int = 10) -> List[Tuple[str, str, int]]:
        """
        Get the most commonly hallucinated parameters.

        Args:
            limit: Number of top hallucinations to return

        Returns:
            List of (tool_name, param_name, count) tuples
        """
        hallucinations = []
        for key, count in self.get_rejection_stats().items():
            if '.' in key:
                tool_name, param_name = key.split('.', 1)
                hallucinations.append((tool_name, param_name, count))

        return hallucinations[:limit]

    def suggest_noise_params_update(self) -> set:
        """
        Analyze rejection stats and suggest params to add to noise filter.

        Returns:
            Set of parameter names that should be added to noise filter
        """
        suggestions = set()

        # If a parameter is rejected across multiple tools, it's likely noise
        param_occurrences = {}
        for key, count in self.rejection_stats.items():
            if '.' in key:
                _, param_name = key.split('.', 1)
                param_occurrences[param_name] = param_occurrences.get(param_name, 0) + 1

        # Suggest params that appear in 3+ different tools
        for param, tool_count in param_occurrences.items():
            if tool_count >= 3:
                suggestions.add(param)

        return suggestions

    def suggest_correction(self, tool_name: str, invalid_param: str) -> Optional[str]:
        """
        Suggest correct parameter name for common mistakes.

        Args:
            tool_name: Tool being called
            invalid_param: Invalid parameter provided

        Returns:
            Suggested correct parameter name or None
        """
        # Common parameter confusion mapping
        corrections = {
            'file_read': {
                'path': 'file_path',
                'filename': 'file_path',
                'file': 'file_path',
                'content': 'file_path',  # Common hallucination
            },
            'file_write': {
                'path': 'file_path',
                'filename': 'file_path',
                'file': 'file_path',
                'data': 'content',
                'text': 'content',
            },
            'bash_execute': {
                'cmd': 'command',
                'shell': 'command',
                'exec': 'command',
            },
            'grep_search': {
                'search': 'pattern',
                'query': 'pattern',
                'text': 'pattern',
                'directory': 'path',
            }
        }

        if tool_name in corrections and invalid_param in corrections[tool_name]:
            return corrections[tool_name][invalid_param]

        return None


# Global instance
tool_schema_validator = ToolSchemaValidator()
